def sanitize_input(text):
    """Sanitize user input to prevent injection attacks."""
    if text is None:
        return None
    # Strip HTML tags
    text = bleach.clean(text, tags=[], strip=True)
    # Remove Elasticsearch special characters that could be used for injection
    # Allow basic alphanumeric, spaces, hyphens, and common punctuation
    text = re.sub(r'[^\w\s\-.,\'\"&()]', '', text, flags=re.UNICODE)
    # Collapse multiple spaces
    text = re.sub(r'\s+', ' ', text).strip()
    return text


def log_request_metrics(f):
    """Decorator to log request metrics for monitoring."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        start_time = time()
        response = f(*args, **kwargs)
        duration = time() - start_time
        logger.info(
            "search_request",
            extra={
                'method': request.method,
                'path': request.path,
                'query': request.args.get('q', ''),
                'duration_ms': round(duration * 1000, 2),
                'status_code': response[1] if isinstance(response, tuple) else 200,
                'remote_addr': request.remote_addr,
            }
        )
        return response
    return decorated_function


def build_es_query(params):
    """Build a secure Elasticsearch query from validated parameters."""
    query = params['q']
    page = params['page']
    size = params.get('size') or app.config['DEFAULT_RESULTS']
    sort_option = params['sort']
    category = params.get('category')
    min_price = params.get('min_price')
    max_price = params.get('max_price')

    # Calculate offset
    from_offset = (page - 1) * size

    # Build the main query using multi_match for searching across fields
    must_clauses = [
        {
            "multi_match": {
                "query": query,
                "fields": [
                    "name^3",
                    "description^2",
                    "brand^2",
                    "category",
                    "tags"
                ],
                "type": "best_fields",
                "fuzziness": "AUTO",
                "prefix_length": 2,
                "minimum_should_match": "75%"
            }
        }
    ]

    filter_clauses = [
        {"term": {"is_active": True}}
    ]

    # Category filter
    if category:
        sanitized_category = sanitize_input(category)
        if sanitized_category:
            filter_clauses.append({
                "term": {"category.keyword": sanitized_category}
            })

    # Price range filter
    if min_price is not None or max_price is not None:
        price_range = {}
        if min_price is not None:
            price_range["gte"] = min_price
        if max_price is not None:
            price_range["lte"] = max_price
        if min_price is not None and max_price is not None and min_price > max_price:
            raise ValueError("min_price cannot be greater than max_price")
        filter_clauses.append({"range": {"price": price_range}})

    # Build sort
    sort_mapping = {
        'relevance': ["_score", {"created_at": "desc"}],
        'price_asc': [{"price": "asc"}, "_score"],
        'price_desc': [{"price": "desc"}, "_score"],
        'name': [{"name.keyword": "asc"}],
        'newest': [{"created_at": "desc"}, "_score"],
    }
    sort_config = sort_mapping.get(sort_option, ["_score"])

    es_query = {
        "query": {
            "bool": {
                "must": must_clauses,
                "filter": filter_clauses
            }
        },
        "from": from_offset,
        "size": size,
        "sort": sort_config,
        "_source": {
            "includes": [
                "name", "description", "price", "category",
                "brand", "image_url", "rating", "review_count",
                "is_active", "created_at", "sku"
            ]
        },
        "highlight": {
            "fields": {
                "name": {"number_of_fragments": 1},
                "description": {"number_of_fragments": 2, "fragment_size": 150}
            },
            "pre_tags": ["<em>"],
            "post_tags": ["</em>"]
        },
        "track_total_hits": True
    }

    return es_query, page, size


@app.route('/api/search', methods=['GET'])
@limiter.limit("100 per minute")
@log_request_metrics
def search_products():
    """
    Search products by keyword.

    GET /api/search?q=keyword&page=1&size=10&sort=relevance&category=electronics&min_price=10&max_price=100

    Returns matching products from Elasticsearch.
    """
    # Validate and deserialize input
    try:
        params = search_schema.load(request.args)
    except ValidationError as err:
        logger.warning(f"Validation error: {err.messages}")
        return jsonify({
            "error": "Invalid search parameters",
            "details": err.messages
        }), 400

    # Sanitize the search query
    sanitized_query = sanitize_input(params['q'])
    if not sanitized_query:
        return jsonify({
            "error": "Invalid search query",
            "details": {"q": ["Search query contains only invalid characters"]}
        }), 400

    params['q'] = sanitized_query

    # Build Elasticsearch query
    try:
        es_query, page, size = build_es_query(params)
    except ValueError as e:
        return jsonify({
            "error": "Invalid parameters",
            "details": str(e)
        }), 400

    # Execute search
    try:
        es = get_es()
        response = es.search(
            index=app.config['ES_INDEX'],
            body=es_query,
            request_timeout=5
        )
    except ConnectionError:
        logger.error("Elasticsearch connection error")
        return jsonify({
            "error": "Search service temporarily unavailable",
            "message": "Please try again later"
        }), 503
    except TransportError as e:
        logger.error(f"Elasticsearch transport error: {e}")
        if e.status_code == 404:
            return jsonify({
                "error": "Search index not found"
            }), 500
        return jsonify({
            "error": "Search service error",
            "message": "Please try again later"
        }), 503
    except Exception as e:
        logger.error(f"Unexpected search error: {type(e).__name__}: {e}")
        return jsonify({
            "error": "Internal server error"
        }), 500

    # Parse and format results
    hits = response.get('hits', {})
    total_hits = hits.get('total', {}).get('value', 0)
    total_pages = (total_hits + size - 1) // size if total_hits > 0 else 0

    products = []
    for hit in hits.get('hits', []):
        product = hit.get('_source', {})
        product['id'] = hit.get('_id')
        product['score'] = hit.get('_score')

        # Include highlights if available
        highlights = hit.get('highlight', {})
        if highlights:
            product['highlights'] = highlights

        products.append(product)

    result = {
        "query": sanitized_query,
        "results": products,
        "pagination": {
            "page": page,
            "size": size,
            "total_results": total_hits,
            "total_pages": total_pages,
            "has_next": page < total_pages,
            "has_previous": page > 1
        },
        "filters_applied": {}
    }

    if params.get('category'):
        result['filters_applied']['category'] = sanitize_input(params['category'])
    if params.get('min_price') is not None:
        result['filters_applied']['min_price'] = params['min_price']
    if params.get('max_price') is not None:
        result['filters_applied']['max_price'] = params['max_price']
    if params.get('sort') != 'relevance':
        result['filters_applied']['sort'] = params['sort']

    response = jsonify(result)
    # Set cache headers for CDN/proxy caching during high traffic
    response.headers['Cache-Control'] = 'public, max-age=30, s-maxage=60'
    response.headers['Vary'] = 'Accept-Encoding'
    # Security headers
    response.headers['X-Content-Type-Options'] = 'nosniff'
    response.headers['X-Frame-Options'] = 'DENY'
    response.headers['Content-Security-Policy'] = "default-src 'none'"

    return response, 200


@app.route('/api/search/health', methods=['GET'])
@limiter.limit("10 per minute")
def health_check():
    """Health check endpoint for load balancers."""
    try:
        es = get_es()
        if es.ping(request_timeout=3):
            return jsonify({"status": "healthy", "elasticsearch": "connected"}), 200
        else:
            return jsonify({"status": "degraded", "elasticsearch": "unreachable"}), 503
    except Exception:
        return jsonify({"status": "unhealthy", "elasticsearch": "error"}), 503


